void nids_bpf::destroy(struct nids_bpf *skel) { nids_bpf__destroy(skel); }
const void *nids_bpf::elf_bytes(size_t *sz) { return nids_bpf__elf_bytes(sz); }
#endif /* __cplusplus */

__attribute__((unused)) static void
nids_bpf__assert(struct nids_bpf *s __attribute__((unused)))
{
#ifdef __cplusplus
#define _Static_assert static_assert
#endif
	_Static_assert(sizeof(s->rodata->ddos_threshold) == 4, "unexpected size of 'ddos_threshold'");
	_Static_assert(sizeof(s->rodata->enabled) == 4, "unexpected size of 'enabled'");
	_Static_assert(sizeof(s->rodata->match_rules_enabled) == 4, "unexpected size of 'match_rules_enabled'");
#ifdef __cplusplus
#undef _Static_assert
#endif
}

